#include <stdio.h>
#include <unistd.h>

int main() {
 pid_t pid;
 pid = fork();
 if (pid < 0) {
 fprintf(stderr, "Fork Failed");
 return 1;
 } else if (pid == 0) {
 execlp("/bin/ls", "ls", NULL);
 } else {
 wait(NULL);
 printf("Child Complete\n");
 }
 return 0;
}

#include <stdio.h>
#include <unistd.h>

int main() {
 int pipefd[2];
 pid_t pid;
 char buffer[256];

 pipe(pipefd);
 pid = fork();
 if (pid == 0) {
 close(pipefd[1]);
 read(pipefd[0], buffer, 256);
 printf("Received from parent: %s\n", buffer);
 } else {
 close(pipefd[0]);
 write(pipefd[1], "Hello, child!\n", 14);
 }
 return 0;
}
